# ── File existence ────────────────────────────────────────────────────────────

@pytest.mark.parametrize("rel_path", INTEGRATION_DOCS + INTEGRATION_SCRIPTS)
def test_file_exists(rel_path):
    assert (ROOT / rel_path).exists(), f"Integration file missing: {rel_path}"


@pytest.mark.parametrize("rel_path", INTEGRATION_SCRIPTS)
def test_script_executable(rel_path):
    path = ROOT / rel_path
    assert path.exists(), f"Script missing: {rel_path}"
    assert os.access(path, os.X_OK), f"Script not executable: {rel_path}"


# ── Attribution audit ─────────────────────────────────────────────────────────

@pytest.mark.parametrize("rel_path", INTEGRATION_DOCS + INTEGRATION_SCRIPTS)
def test_no_external_attribution(rel_path):
    path = ROOT / rel_path
    if not path.exists():
        pytest.skip(f"File not found: {rel_path}")
    content = path.read_text()
    for phrase in ATTRIBUTION_STRINGS:
        assert phrase not in content, (
            f"External attribution found in {rel_path}: {phrase!r}"
        )


