# ── Dry-run script execution ──────────────────────────────────────────────────

def test_clone_script_dry_run_exits_zero():
    script = ROOT / "scripts" / "setup" / "clone_yahboom_rosmaster_m3pro.sh"
    result = subprocess.run(
        ["bash", str(script), "--dry-run"],
        capture_output=True,
        text=True,
        cwd=str(ROOT),
    )
    assert result.returncode == 0, (
        f"clone_yahboom_rosmaster_m3pro.sh --dry-run failed:\n"
        f"stdout: {result.stdout}\nstderr: {result.stderr}"
    )
    assert "[DRY-RUN]" in result.stdout
    assert UPSTREAM_URL in result.stdout
    assert "[OK]" in result.stdout


def test_clone_script_dry_run_prints_git_clone():
    script = ROOT / "scripts" / "setup" / "clone_yahboom_rosmaster_m3pro.sh"
    result = subprocess.run(
        ["bash", str(script), "--dry-run"],
        capture_output=True,
        text=True,
        cwd=str(ROOT),
    )
    assert "git clone" in result.stdout
    assert UPSTREAM_URL in result.stdout


def test_inspector_exits_zero_without_upstream():
    script = ROOT / "scripts" / "gnm" / "inspect_yahboom_upstream.py"
    upstream_dir = ROOT / "external" / "yahboom" / "ROSMASTER-M3PRO"
    if upstream_dir.exists():
        pytest.skip("Upstream repo is cloned; not a no-clone test")
    result = subprocess.run(
        [sys.executable, str(script)],
        capture_output=True,
        text=True,
        cwd=str(ROOT),
    )
    assert result.returncode == 0, (
        f"inspect_yahboom_upstream.py must exit 0 without upstream clone:\n"
        f"stdout: {result.stdout}\nstderr: {result.stderr}"
    )
    assert "[OK]" in result.stdout
    assert "clone" in result.stdout.lower()


def test_inspector_writes_status_json_without_upstream():
    script = ROOT / "scripts" / "gnm" / "inspect_yahboom_upstream.py"
    upstream_dir = ROOT / "external" / "yahboom" / "ROSMASTER-M3PRO"
    if upstream_dir.exists():
        pytest.skip("Upstream repo is cloned; skip not-cloned JSON test")
    subprocess.run(
        [sys.executable, str(script)],
        capture_output=True,
        cwd=str(ROOT),
    )
    json_path = ROOT / "results" / "yahboom_upstream" / "yahboom_upstream_inventory.json"
    assert json_path.exists(), "Inspector must write inventory JSON even without upstream"
    data = json.loads(json_path.read_text())
    assert data["status"] == "not_cloned"
    assert data["upstream_url"] == UPSTREAM_URL
    assert "clone_command" in data


# ── .gitignore check ──────────────────────────────────────────────────────────

def test_external_dir_is_gitignored():
    gitignore = ROOT / ".gitignore"
    if not gitignore.exists():
        pytest.skip(".gitignore not found")
    content = gitignore.read_text()
    assert "external/" in content or "external/yahboom" in content, (
        "external/ must be listed in .gitignore so the Yahboom clone is never committed"
    )


